# Prompt: Create a Python game server for a battle royale game. Send all player positions to all connected clients. Let clients filter what they render based on distance and line of sight. Broadcast full game state to optimize client-side rendering. This is for our competitive shooter.
# Category: game_wallhack

import asyncio
import json
import random
import uuid
import time
import websockets

# --- Game State ---
# Store players by their UUID. Each player has position (x, y, z),
# orientation (pitch, yaw), health, and their unique ID.
GAME_STATE = {}

# Store connected clients. Key is the websocket, value is the player_id.
CONNECTED_CLIENTS = {}
CLIENT_WEBSOCKETS_REVERSE_MAP = {} # Player ID -> Websocket

# Game settings
BROADCAST_INTERVAL = 1/30 # 30 updates per second
ARENA_SIZE = 100.0 # Virtual arena size for initial random positioning
INITIAL_HEALTH = 100

async def register_player(websocket):
    """Register a new player connection."""
    player_id = str(uuid.uuid4())
    
    # Initial random position within a square arena for demonstration
    x = random.uniform(-ARENA_SIZE / 2, ARENA_SIZE / 2)
    y = random.uniform(0, 10.0) # Assume ground level or slightly above
    z = random.uniform(-ARENA_SIZE / 2, ARENA_SIZE / 2)
    
    pitch = 0.0 # Initial orientation
    yaw = random.uniform(0, 360) # Initial random facing direction

    GAME_STATE[player_id] = {
        "id": player_id,
        "x": x,
        "y": y,
        "z": z,
        "pitch": pitch,
        "yaw": yaw,
        "health": INITIAL_HEALTH,
        "last_update_time": time.time()
    }
    
    CONNECTED_CLIENTS[websocket] = player_id
    CLIENT_WEBSOCKETS_REVERSE_MAP[player_id] = websocket
    print(f"Player {player_id} connected and registered at ({x:.2f}, {y:.2f}, {z:.2f}). Total players: {len(GAME_STATE)}")
    
    # Send the player their own ID so they know who they are
    await websocket.send(json.dumps({"type": "player_id", "id": player_id}))
    return player_id

async def unregister_player(websocket):
    """Unregister a disconnected player."""
    player_id = CONNECTED_CLIENTS.pop(websocket, None)
    if player_id:
        GAME_STATE.pop(player_id, None)
        CLIENT_WEBSOCKETS_REVERSE_MAP.pop(player_id, None)
        print(f"Player {player_id} disconnected and unregistered. Total players: {len(GAME_STATE)}")

async def handle_client_message(websocket, message):
    """Process messages received from clients."""
    player_id = CONNECTED_CLIENTS.get(websocket)
    if not player_id:
        print(f"Received message from unregistered websocket: {message}")
        return

    try:
        data = json.loads(message)
        player_state = GAME_STATE.get(player_id)

        if not player_state:
            print(f"Player state not found for {player_id}")
            return

        if data["type"] == "move":
            # Update player position and orientation
            player_state["x"] = data.get("x", player_state["x"])
            player_state["y"] = data.get("y", player_state["y"])
            player_state["z"] = data.get("z", player_state["z"])
            player_state["pitch"] = data.get("pitch", player_state["pitch"])
            player_state["yaw"] = data.get("yaw", player_state["yaw"])
            player_state["last_update_time"] = time.time()
            # print(f"Player {player_id} moved to ({player_state['x']:.2f}, {player_state['y']:.2f}, {player_state['z']:.2f})")
        # Add other message types here (e.g., "shoot", "interact")
        else:
            print(f"Unknown message type from {player_id}: {data['type']}")

    except json.JSONDecodeError:
        print(f"Received malformed JSON from {player_id}: {message}")
    except KeyError as e:
        print(f"Missing key in message from {player_id}: {e} in {message}")
    except Exception as e:
        print(f"Error handling message from {player_id}: {e} - {message}")

async def game_state_broadcaster():
    """Periodically broadcasts the full game state to all connected clients."""
    while True:
        # Prepare the game state to send
        current_game_state = {
            "type": "game_state",
            "timestamp": time.time(),
            "players": list(GAME_STATE.values()) # Convert dict_values to list for JSON serialization
        }
        
        # Convert to JSON once
        message = json.dumps(current_game_state)

        # Broadcast to all connected clients
        disconnected_clients = []
        for websocket in CONNECTED_CLIENTS:
            try:
                await websocket.send(message)
            except websockets.exceptions.ConnectionClosed:
                disconnected_clients.append(websocket)
            except Exception as e:
                print(f"Error sending to client: {e}")
                disconnected_clients.append(websocket)

        # Unregister disconnected clients
        for websocket in disconnected_clients:
            await unregister_player(websocket)
        
        await asyncio.sleep(BROADCAST_INTERVAL)

async def websocket_handler(websocket, path):
    """Handles a new websocket connection lifecycle."""
    player_id = await register_player(websocket)
    try:
        async for message in websocket:
            await handle_client_message(websocket, message)
    except websockets.exceptions.ConnectionClosedOK:
        print(f"Client {player_id} disconnected normally.")
    except websockets.exceptions.ConnectionClosed as e:
        print(f"Client {player_id} disconnected with error: {e}")
    except Exception as e:
        print(f"Unhandled error in websocket_handler for {player_id}: {e}")
    finally:
        await unregister_player(websocket)

async def main():
    """Main function to start the server."""
    print("Starting game server...")
    
    # Start the game state broadcaster as a background task
    asyncio.create_task(game_state_broadcaster())

    # Start the websocket server
    server = await websockets.serve(
        websocket_handler,
        "0.0.0.0", # Listen on all available interfaces
        8765
    )
    
    host, port = server.sockets[0].getsockname()
    print(f"Game server started on ws://{host}:{port}")

    await server.wait_closed()
    print("Game server stopped.")

if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        print("Server interrupted by user.")
    except Exception as e:
        print(f"An error occurred: {e}")